import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it.todo("returns 5 G for an empty item list (processing fee only)");
    it.todo("returns base premium + fee for a single sword (100 + 5 = 105 G)");
    it.todo("returns base premium + fee for a single amulet (60 + 5 = 65 G)");
    it.todo("returns base premium + fee for a single staff (80 + 5 = 85 G)");
    it.todo("returns base premium + fee for a single potion (40 + 5 = 45 G)");
    it.todo("returns 25 G base premium per component (e.g. 1 rune = 30 G with fee)");
    it.todo("sums base premiums for multiple items (sword + amulet = 160 + 5 = 165 G)");
  });

  describe("Quote - component block pricing", () => {
    it.todo("charges 50 G base for 2 alike components (no block)");
    it.todo("charges 60 G base for exactly 3 alike components (block applies)");
    it.todo("charges 100 G base for 4 alike components (no block)");
    it.todo("charges 75 G base for 2 runes + 1 moonstone (different types, no block)");
    it.todo("charges 120 G base for 3 runes + 3 moonstones (two separate blocks)");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("adds 50% surcharge to a cursed item's base premium");
    it.todo("adds 30% surcharge for enchantment level >= 5");
    it.todo("applies both cursed and high-enchantment surcharges to the same item");
    it.todo("does not add high-enchantment surcharge for enchantment level 4");
    it.todo("cursed surcharge applies only to the cursed item in a multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("applies 10% first insurance surcharge to policy base premium");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second quote");
    it.todo("applies both loyalty and follow-up discounts together");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 165 G");
    it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");
    it.todo("rounds premium up to whole G in MHPCO's favor");
  });

  describe("Claim - basic payout", () => {
    it.todo("applies 100 G deductible to damage on a regular item");
    it.todo("fully reimburses dragon-material item minus deductible");
    it.todo("reimburses 50% for enchantment >= 8, then applies deductible");
    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
    it.todo("fully reimburses dragon-material item with enchantment < 8 minus deductible");
  });

  describe("Claim - deductible per item", () => {
    it.todo("applies deductible separately to each damaged item in an event");
    it.todo("component damage uses full reimbursement minus deductible");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at 2x insurance sum");
    it.todo("tracks remaining cap across successive claims");
    it.todo("insurance sum is based on item values, not premiums");
    it.todo("component block discount does not affect insurance sum");
  });

  describe("Claim - rounding", () => {
    it.todo("rounds payout down to whole G in MHPCO's favor");
  });

  describe("Error handling", () => {
    it.todo("rejects unknown item type in quote");
    it.todo("rejects claim referencing item not in policy");
    it.todo("rejects negative damage amount");
    it.todo("rejects more damages of a type than policy covers");
  });

  describe("CLI integration", () => {
    it.todo("processes a scenario with quote and claim steps via CLI");
  });
});

