import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5 G for an empty item list (processing fee only)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("returns base premium + fee for a single sword (100 + 5 = 105 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it.todo("returns base premium + fee for a single amulet (60 + 5 = 65 G)");
    it.todo("returns base premium + fee for a single staff (80 + 5 = 85 G)");
    it.todo("returns base premium + fee for a single potion (40 + 5 = 45 G)");
    it.todo("returns 25 G base premium per component (e.g. 1 rune = 30 G with fee)");
    it.todo("sums base premiums for multiple items (sword + amulet = 160 + 5 = 165 G)");
  });

