const PROCESSING_FEE = 5;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);

const basePremium = (item: any): number =>
  BASE_PREMIUMS[item.type] ?? 0;

const quotePremium = (items: any[]): number => {
  const components: Record<string, number> = {};
  const nonComponents: any[] = [];
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      components[item.type] = (components[item.type] ?? 0) + 1;
    } else {
      nonComponents.push(item);
    }
  }
  let premium = nonComponents.reduce((sum: number, item: any) => sum + basePremium(item), 0);
  for (const [type, count] of Object.entries(components)) {
    if (count === 3) {
      premium += COMPONENT_BLOCK_PREMIUM;
    } else {
      premium += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }
  return premium + PROCESSING_FEE;
};

