describe("Quote - component block pricing", () => {
  it("charges 50 G base for 2 alike components (no block)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 55 });
  });
  it("charges 60 G base for exactly 3 alike components (block applies)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("charges 100 G base for 4 alike components (no block)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("charges 75 G base for 2 runes + 1 moonstone (different types, no block)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 80 });
  });
  it("charges 120 G base for 3 runes + 3 moonstones (two separate blocks)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 125 });
  });
});

describe("Quote - item-specific modifiers", () => {
  it("adds 50% surcharge to a cursed item's base premium", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: true },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 155 });
  });
  it("adds 30% surcharge for enchantment level >= 5", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 5, cursed: false },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 135 });
  });
  it("applies both cursed and high-enchantment surcharges to the same item", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 5, cursed: true },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 185 });
  });
  it("does not add high-enchantment surcharge for enchantment level 4", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 4, cursed: false },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("cursed surcharge applies only to the cursed item in a multi-item policy", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: true },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    expect(result.results[0]).toEqual({ premium: 215 });
  });
});

